import React from "react";

function About() {

  return (

    <div className="container">

      <h1>About This Project</h1>

      <p>

        The Women Safety Monitoring System helps users travel safely by
        tracking live location and sending emergency alerts.

      </p>

      <ul>

        <li>Live GPS tracking</li>
        <li>Automatic danger detection</li>
        <li>Emergency SOS alerts</li>
        <li>Nearest police station finder</li>
        <li>Live location sharing to parents</li>

      </ul>

    </div>

  )

}

export default About;
